  useEffect(() => {
    async function fetchData() {
      if (!isAuthenticated) {
        // Generate mock data for landed/preview state
        setData(generateMockData());
        setIsLoading(false);
        return;
      }

      try {
        const history = await vitalsAPI.getTimelineData(24);
        // Transform backend VitalReading[] to TimelinePoint[]
        // This is a simplified transformation; in reality, we'd group by timestamp
        const transformed: TimelinePoint[] = []; 
        // For now, let's keep the mock structure but ideally this maps to real data
        // If data is empty, use mock
        if (history.length === 0) {
          setData(generateMockData());
        } else {
          // Mapping logic would go here if backend returns time-series points
          setData(generateMockData()); // Fallback to mock for consistent visual demo
        }
      } catch (err) {
        console.error("Timeline fetch failed", err);
        setData(generateMockData());
      } finally {
        setIsLoading(false);
      }
