                        </div>
                      </div>
                    ))}
                  </div>
                </div>

                {/* Clinical Summaries */}
                <div className="space-y-2">
                   {result.clinical_summary.map((summary, idx) => (
                     <div key={idx} className="flex gap-3 text-sm text-slate-400 pl-2 border-l border-blue-500/30">
