    dbPromise = openDB<MedGenieDB>('medgenie-db', 2, {
      upgrade(db) {
        if (!db.objectStoreNames.contains('vitals')) {
          const vitalsStore = db.createObjectStore('vitals', { keyPath: 'id' });
          vitalsStore.createIndex('by-timestamp', 'timestamp');
          vitalsStore.createIndex('by-sync', 'synced' as any);
        }

        if (!db.objectStoreNames.contains('alerts')) {
          const alertsStore = db.createObjectStore('alerts', { keyPath: 'id' });
          alertsStore.createIndex('by-timestamp', 'timestamp');
          alertsStore.createIndex('by-sync', 'synced' as any);
        }

        if (!db.objectStoreNames.contains('sync_queue')) {
          db.createObjectStore('sync_queue', { keyPath: 'id', autoIncrement: true });
        }
      },
    });
  }
  return dbPromise;
};

// --- Helper Functions for useOfflineSync ---

export const getUnsyncedLogs = async (): Promise<any[]> => {
  const db = await getDB();
  const tx = db.transaction(['vitals', 'alerts'], 'readonly');
  const vitals = await tx.objectStore('vitals').index('by-sync').getAll(0 as any); // 0 for false
  const alerts = await tx.objectStore('alerts').index('by-sync').getAll(0 as any);

  return [...vitals.map(v => ({...v, type: 'biometric', data: v})), 
          ...alerts.map(a => ({...a, type: 'alert', data: a}))];
};

export const markLogSynced = async (id: string, storeName: 'vitals' | 'alerts') => {
  const db = await getDB();
  const tx = db.transaction(storeName, 'readwrite');
  const store = tx.objectStore(storeName);
  const val = await store.get(id);
  if (val) {
    val.synced = true;
    await store.put(val);
  }
  await tx.done;
};

export const addToSyncQueue = async (action: 'CREATE' | 'UPDATE' | 'DELETE', store: 'vitals' | 'alerts', data: any) => {
  const db = await getDB();
  await db.add('sync_queue', {
    action,
    store,
    data,
    timestamp: Date.now(),
  });
};

export const saveLogOffline = async (log: HealthLog) => {
  const db = await getDB();
  const storeName = log.type === 'biometric' ? 'vitals' : 'alerts';

  // Map HealthLog to store structure
  if (log.type === 'biometric') {
    await db.put('vitals', {
      id: log.id,
      metric_type: log.data.metric_type,
      value: log.data.value,
      unit: log.data.unit,
      timestamp: log.timestamp,
      synced: false
    });
  } else {
    await db.put('alerts', {
      id: log.id,
      type: log.type,
      message: log.data.text || log.data.message || "Manual symptom log",
      severity: log.data.severity || 'info',
      timestamp: log.timestamp,
      synced: false
    });
  }

  // Also add to sync queue for Background Sync
  await addToSyncQueue('CREATE', storeName, log.data);
};

"use client";

import React, { createContext, useContext, useEffect, useState, useCallback, ReactNode } from "react";
import { vitalsAPI, type VitalReading, type DigitalTwinState, vitalsSocket } from "@/lib/api";
import { useAuth } from "@/lib/auth";

interface RealtimeContextType {
  vitals: Record<string, VitalReading>;
  twinState: DigitalTwinState | null;
  isConnected: boolean;
  isSimulated: boolean;
  lastUpdate: Date | null;
  anomalies: any[]; // New: Real-time health alerts
}

const RealtimeContext = createContext<RealtimeContextType | undefined>(undefined);

export function RealtimeProvider({ children }: { children: ReactNode }) {
  const { user, isAuthenticated } = useAuth();
  const [vitals, setVitals] = useState<Record<string, VitalReading>>({});
  const [twinState, setTwinState] = useState<DigitalTwinState | null>(null);
  const [isConnected, setIsConnected] = useState(false);
  const [isSimulated, setIsSimulated] = useState(true);
  const [lastUpdate, setLastUpdate] = useState<Date | null>(null);
  const [anomalies, setAnomalies] = useState<any[]>([]);

  const fetchInitialData = useCallback(async () => {
    try {
      const [latestVitals, state] = await Promise.all([
        vitalsAPI.getLatest(),
        vitalsAPI.getTwinState(),
      ]);

      const vitalsMap: Record<string, VitalReading> = {};
      latestVitals.forEach((v) => {
        vitalsMap[v.metric_type] = v;
      });

      setVitals(vitalsMap);
      setTwinState(state);
      setIsSimulated(false);
      setLastUpdate(new Date());
    } catch (err) {
      console.warn("Realtime API failed, falling back to simulated data", err);
      // Initialize with mock data if API fails or for demo
      const mockVitals: Record<string, VitalReading> = {
        heart_rate: { value: 72, unit: "bpm", metric_type: "heart_rate", recorded_at: new Date().toISOString() } as any,
        blood_pressure: { value: 120, unit: "mmHg", metric_type: "blood_pressure", recorded_at: new Date().toISOString(), metadata: { systolic: 120, diastolic: 80 } } as any,
        oxygen_saturation: { value: 98, unit: "%", metric_type: "oxygen_saturation", recorded_at: new Date().toISOString() } as any,
        temperature: { value: 36.6, unit: "°C", metric_type: "temperature", recorded_at: new Date().toISOString() } as any,
        respiratory_rate: { value: 16, unit: "br/m", metric_type: "respiratory_rate", recorded_at: new Date().toISOString() } as any,
      };
      setVitals(mockVitals);
    }
  }, []);

  useEffect(() => {
    if (!isAuthenticated || !user) {
      setIsSimulated(true);
      return;
    }

    fetchInitialData();

    // Connect WebSocket
    const stopListening = vitalsSocket.on("vital_update", (data: any) => {
      setVitals((prev) => ({
        ...prev,
        [data.metric_type]: data as VitalReading,
      }));
      setLastUpdate(new Date());
    });

    const stopAnomalyListening = vitalsSocket.on("anomaly_alert", (data: any) => {
      setAnomalies((prev) => [data, ...prev].slice(0, 50)); // Keep last 50
    });

    const stopConnListening = vitalsSocket.on("connection", (data: any) => {
      setIsConnected(data.status === "connected");
    });

    vitalsSocket.connect(user.id);

    return () => {
      stopListening();
      stopAnomalyListening();
      stopConnListening();
      vitalsSocket.disconnect();
    };
  }, [isAuthenticated, user, fetchInitialData]);

  // Simulation fallback for vitals if no real stream is active
  useEffect(() => {
    const interval = setInterval(() => {
      if (isConnected) return; // Don't simulate if we have a real connection

      setVitals((prev) => {
        const next = { ...prev };
        Object.keys(next).forEach((key) => {
          const v = next[key];
          if (!v) return;
          const change = (Math.random() - 0.5) * 2;
          next[key] = { 
            ...v, 
            value: Number((v.value + (v.value > 0 ? change : 0)).toFixed(1)),
            recorded_at: new Date().toISOString()
          };
        });
        return next;
      });
      setLastUpdate(new Date());
    }, 3000);

    return () => clearInterval(interval);
  }, [isConnected]);

  return (
    <RealtimeContext.Provider value={{ vitals, twinState, isConnected, isSimulated, lastUpdate, anomalies }}>
      {children}
    </RealtimeContext.Provider>
  );
}

export function useRealtime() {
  const context = useContext(RealtimeContext);
  if (context === undefined) {
    throw new Error("useRealtime must be used within a RealtimeProvider");
  }
  return context;
}
